 function scoreSignalForChart(signal = {}) {
 const action = String(signal.shortlistAction || signal.decision?.action || '').toUpperCase();
 const actionBoost = action.includes('TRADE') ? 30 : action.includes('CLOSE') ? 16 : action.includes('WATCH') ? 8 : 0;
 const mtfBoost = signal.mtfConfirmed ? 10 : 0;
 return Number(signal.tradeQuality?.score || 0) * 1.4
 + Number(signal.score || 0)
 + actionBoost
 + mtfBoost
 + Number(signal.rsComposite || 0);
 }

 function pickBestChartSignal(scanResults = [], shortlist = []) {
 const source = Array.isArray(shortlist) && shortlist.length ? shortlist : scanResults;
 return (Array.isArray(source) ? source : [])
 .filter(signal => String(signal?.symbol || '').trim())
 .slice()
 .sort((a, b) => scoreSignalForChart(b) - scoreSignalForChart(a))[0] || null;
 }

