 async function closeChartReviewTab(tabId = '') {
 const safeId = sanitizeReviewTabId(tabId);
 const current = await getChartState();
 const tabs = sanitizeChartReviewTabs(current.chartReviewTabs || []);
 const closingIndex = tabs.findIndex(item => item.id === safeId);
 if (closingIndex < 0) return current;
 const closingTab = tabs[closingIndex];
 const nextTabs = tabs.filter(item => item.id !== safeId);
 const closingActive = String(current.activeChartReviewTabId || '') === safeId;
 if (!closingActive) {
 return setChartState({ chartReviewTabs: nextTabs });
 }
 const nextActive = nextTabs[Math.max(0, Math.min(closingIndex, nextTabs.length - 1))] || null;
 if (!nextActive) {
 const next = await setChartState({
 chartReviewTabs: [],
 activeChartReviewTabId: '',
 chartReviewOverlayOpen: false,
 chartTradingDraft: null,
 chartTradingMode: 'select',
 });
 if (current.chartReviewOverlayOpen) {
 unmountChartReviewOverlay();
 } else {
 returnToChartReviewSource(closingTab);
 }
 return next;
 }
 await setChartState({
 chartReviewTabs: nextTabs,
 activeChartReviewTabId: nextActive.id,
 });
 return activateChartReviewTab(nextActive.id);
 }

