 function findNearestCandleIndex(candles = [], ts = 0) {
 const target = normalizeTsMs(ts);
 if (!target || !Array.isArray(candles) || !candles.length) return -1;
 let bestIndex = -1;
 let bestGap = Number.POSITIVE_INFINITY;
 candles.forEach((candle, index) => {
 const gap = Math.abs(Number(candle.time || 0) - target);
 if (gap < bestGap) {
 bestGap = gap;
 bestIndex = index;
 }
 });
 return bestIndex;
 }

 function getVisibleWindow(candles = [], state = {}) {
 const total = Array.isArray(candles) ? candles.length : 0;
 if (!total) return { startIndex: 0, endIndex: -1, visibleCandles: [], baselineCount: 0 };
 const replayMode = normalizeReplayMode(state.replayMode);
 const baseVisibleCount = Math.max(24, Math.min(total, Math.round(Number(state.visibleCandleCount || defaultVisibleCount(state.timeframe)) || defaultVisibleCount(state.timeframe))));
 if (!state.replaySeed) {
 if (replayMode?.active) {
 const defaultCursor = Math.max(0, total - Math.max(12, Math.round(baseVisibleCount * 0.75)));
 const cursorIndex = Math.max(0, Math.min(total - 1, Number.isFinite(Number(replayMode.cursorIndex)) ? Math.round(Number(replayMode.cursorIndex)) : defaultCursor));
 const startIndex = Math.max(0, cursorIndex - baseVisibleCount + 1);
 return {
 startIndex,
 endIndex: cursorIndex,
 visibleCandles: candles.slice(startIndex, cursorIndex + 1),
 baselineCount: defaultVisibleCount(state.timeframe),
 replayCursorIndex: cursorIndex,
 };
 }
 const visibleCount = baseVisibleCount;
 return {
 startIndex: Math.max(0, total - visibleCount),
 endIndex: total - 1,
 visibleCandles: candles.slice(-visibleCount),
 baselineCount: defaultVisibleCount(state.timeframe),
 };
 }
 const replaySeed = state.replaySeed;
 const beforeCount = Math.max(10, Number(replaySeed.beforeCount || 60));
 const afterCount = Math.max(10, Number(replaySeed.afterCount || 60));
 const anchorTimes = [];
 if (replaySeed.entryTs) anchorTimes.push(replaySeed.entryTs);
 if (replaySeed.exitTs) anchorTimes.push(replaySeed.exitTs);
 (Array.isArray(replaySeed.markers) ? replaySeed.markers : []).forEach(marker => {
 const ts = normalizeTsMs(marker.ts);
 if (ts) anchorTimes.push(ts);
 });
 const anchorIndexes = anchorTimes.map(ts => findNearestCandleIndex(candles, ts)).filter(index => index >= 0);
 const minAnchorIndex = anchorIndexes.length ? Math.min(...anchorIndexes) : Math.max(0, total - defaultVisibleCount(state.timeframe));
 const maxAnchorIndex = anchorIndexes.length ? Math.max(...anchorIndexes) : total - 1;
 const baselineStart = Math.max(0, minAnchorIndex - beforeCount);
 const baselineEnd = Math.min(total - 1, maxAnchorIndex + afterCount);
 const baselineCount = Math.max(24, baselineEnd - baselineStart + 1);
 const visibleCount = Math.max(baselineCount, Math.min(total, Math.round(Number(state.visibleCandleCount || baselineCount) || baselineCount)));
 if (replayMode?.active) {
 const entryIndex = replaySeed.entryTs ? findNearestCandleIndex(candles, replaySeed.entryTs) : minAnchorIndex;
 const defaultCursor = Math.max(0, entryIndex >= 0 ? entryIndex : baselineStart);
 const cursorFromMode = Number(replayMode.cursorIndex);
 const cursorIndex = Math.max(0, Math.min(total - 1, Number.isFinite(cursorFromMode) ? Math.round(cursorFromMode) : defaultCursor + Number(replaySeed.cursorOffset || 0)));
 const startIndex = Math.max(0, cursorIndex - visibleCount + 1);
 return {
 startIndex,
 endIndex: cursorIndex,
 visibleCandles: candles.slice(startIndex, cursorIndex + 1),
 baselineCount,
 replayCursorIndex: cursorIndex,
 };
 }
 const maxStart = Math.max(0, total - visibleCount);
 const startIndex = Math.max(0, Math.min(maxStart, baselineStart + Number(replaySeed.cursorOffset || 0)));
 const endIndex = Math.min(total - 1, startIndex + visibleCount - 1);
 return {
 startIndex,
 endIndex,
 visibleCandles: candles.slice(startIndex, endIndex + 1),
 baselineCount,
 };
 }

 function medianNumber(values = []) {
 const sorted = values.filter(value => Number.isFinite(value) && value > 0).sort((a, b) => a - b);
 if (!sorted.length) return 0;
 const middle = Math.floor(sorted.length / 2);
 return sorted.length % 2 ? sorted[middle] : ((sorted[middle - 1] + sorted[middle]) / 2);
 }

 function getEventCandleTimes(candles = [], state = {}) {
 if (state.hideEventCandles !== true || !Array.isArray(candles) || candles.length < 12) return new Set();
 const recent = candles.slice(-Math.min(candles.length, 900));
 const ranges = recent.map(candle => Math.abs(Number(candle.high || 0) - Number(candle.low || 0)));
 const medianRange = medianNumber(ranges);
 if (!(medianRange > 0)) return new Set();
 const eventTimes = new Set();
 candles.forEach((candle, index) => {
 const high = Number(candle.high || 0);
 const low = Number(candle.low || 0);
 const open = Number(candle.open || 0);
 const close = Number(candle.close || 0);
 const time = Number(candle.time || 0);
 if (!(time > 0) || !(high > 0) || !(low > 0) || high < low) return;
 const range = high - low;
 const body = Math.max(Math.abs(close - open), medianRange * 0.35);
 const upperWick = Math.max(0, high - Math.max(open, close));
 const lowerWick = Math.max(0, Math.min(open, close) - low);
 const prev = candles[index - 1] || {};
 const next = candles[index + 1] || {};
 const nearbyClose = medianNumber([prev.close, close, next.close].map(Number));
 const farFromNearby = nearbyClose > 0 && (Math.abs(high - nearbyClose) / nearbyClose > 0.045 || Math.abs(low - nearbyClose) / nearbyClose > 0.045);
 const rangeOutlier = range > Math.max(medianRange * 8, nearbyClose > 0 ? nearbyClose * 0.035 : 0);
 const wickOutlier = Math.max(upperWick, lowerWick) > Math.max(body * 5, medianRange * 6);
 if (rangeOutlier && (wickOutlier || farFromNearby)) eventTimes.add(time);
 });
 return eventTimes;
 }

 function compareRankedKeyZones(a = {}, b = {}, referencePrice = 0) {
 const touchDiff = Number(b.touches || 0) - Number(a.touches || 0);
 if (touchDiff) return touchDiff;
 const strengthDiff = Number(b.strengthPct || 0) - Number(a.strengthPct || 0);
 if (strengthDiff) return strengthDiff;
 const timeframePriority = (zone) => (String(zone.tf || '').trim().toUpperCase() === '1D' ? 2 : 1);
 const timeframeDiff = timeframePriority(b) - timeframePriority(a);
 if (timeframeDiff) return timeframeDiff;
 if (referencePrice > 0) {
 const distanceDiff = Math.abs(Number(a.price || 0) - referencePrice) - Math.abs(Number(b.price || 0) - referencePrice);
 if (distanceDiff) return distanceDiff;
 }
 const widthDiff = Math.abs(Number(a.zoneHigh || 0) - Number(a.zoneLow || 0)) - Math.abs(Number(b.zoneHigh || 0) - Number(b.zoneLow || 0));
 if (widthDiff) return widthDiff;
 return Math.abs(Number(a.price || 0)) - Math.abs(Number(b.price || 0));
 }

 function keyZoneTimeframePriority(zone = {}) {
 const tf = String(zone.tf || '').trim().toUpperCase();
 if (tf === '1D') return 1.25;
 if (tf === 'COMBINED') return 1.18;
 return 1;
 }

 function keyZoneMergeTolerance(zone = {}, referencePrice = 0, settings = {}) {
 const price = Number(zone.price || referencePrice || 0);
 const width = Math.abs(Number(zone.zoneHigh || price) - Number(zone.zoneLow || price));
 const tf = String(zone.tf || '').trim().toUpperCase();
 const chartTf = normalizeTimeframe(settings.chartTimeframe || '');
 const dailyContext = tf === '1D' || chartTf === '1d' || chartTf === '1h' || chartTf === '4h';
 const pct = dailyContext ? 0.0035 : 0.0022;
 return Math.max(width * 1.4, price > 0 ? price * pct : 0);
 }

 function mergeNearbyKeyZones(zones = [], referencePrice = 0, settings = {}) {
 const sorted = (Array.isArray(zones) ? zones : [])
 .filter(zone => Number(zone.price || 0) > 0)
 .sort((a, b) => Number(a.price || 0) - Number(b.price || 0));
 const clusters = [];
 sorted.forEach(zone => {
 const price = Number(zone.price || 0);
 const match = clusters.find(cluster => {
 const tolerance = Math.max(keyZoneMergeTolerance(cluster, referencePrice, settings), keyZoneMergeTolerance(zone, referencePrice, settings));
 return Math.abs(price - Number(cluster.price || 0)) <= tolerance;
 });
 if (!match) {
 clusters.push({
 ...zone,
 sourcePivots: Array.isArray(zone.sourcePivots) ? zone.sourcePivots.slice() : [],
 });
 return;
 }
 const oldWeight = Math.max(1, Number(match.touches || 1));
 const newWeight = Math.max(1, Number(zone.touches || 1));
 const totalWeight = oldWeight + newWeight;
 match.price = ((Number(match.price || 0) * oldWeight) + (price * newWeight)) / totalWeight;
 match.zoneLow = Math.min(Number(match.zoneLow || match.price), Number(zone.zoneLow || price));
 match.zoneHigh = Math.max(Number(match.zoneHigh || match.price), Number(zone.zoneHigh || price));
 match.touches = Math.max(Number(match.touches || 0), 0) + Math.max(Number(zone.touches || 0), 0);
 match.strengthPct = Math.max(Number(match.strengthPct || 0), Number(zone.strengthPct || 0));
 match.sourcePivots = [
 ...(Array.isArray(match.sourcePivots) ? match.sourcePivots : []),
 ...(Array.isArray(zone.sourcePivots) ? zone.sourcePivots : []),
 ].slice(-24);
 });
 return clusters;
 }

 function scoreKeyZone(zone = {}, referencePrice = 0, kind = '') {
 const price = Number(zone.price || 0);
 const touches = Math.max(0, Number(zone.touches || 0));
 const strength = Math.max(0, Number(zone.strengthPct || 0));
 const providedScore = Math.max(0, Number(zone.smartScore || zone.score || 0));
 const distancePct = referencePrice > 0 && price > 0 ? Math.abs(price - referencePrice) / referencePrice : 1;
 const proximityScore = Math.max(0, 32 - (distancePct * 900));
 const directionalBonus = referencePrice > 0
 ? ((kind === 'resistance' && price >= referencePrice) || (kind === 'support' && price <= referencePrice) ? 18 : -18)
 : 0;
 const width = Math.abs(Number(zone.zoneHigh || price) - Number(zone.zoneLow || price));
 const widthPenalty = referencePrice > 0 ? Math.min(10, (width / referencePrice) * 1800) : 0;
 const latestPivotTs = Math.max(...(Array.isArray(zone.sourcePivots) ? zone.sourcePivots : []).map(pivot => Number(pivot.ts || 0)).filter(Boolean), 0);
 const ageDays = latestPivotTs > 0 ? Math.max(0, (Date.now() - latestPivotTs) / 86400000) : 365;
 const recencyScore = Math.max(0, 22 - ageDays * 1.6);
 const mtfBonus = String(zone.tf || '').trim().toUpperCase() === 'COMBINED' ? 12 : 0;
 const metricBonus = Math.min(32, Number(zone.rejectionCount || 0) * 2 + Number(zone.breakoutRetests || 0) * 6 + Number(zone.consolidationBars || 0) * 0.6 + Number(zone.volumeScore || 0) * 0.5);
 const computedScore = (touches * 10) + (strength * 0.75) + proximityScore + directionalBonus + (keyZoneTimeframePriority(zone) * 8) + recencyScore + mtfBonus + metricBonus - widthPenalty;
 return Math.max(providedScore, computedScore);
 }

 function keyLevelDistancePct(zone = {}, referencePrice = 0) {
 const price = Number(zone.price || 0);
 return referencePrice > 0 && price > 0 ? Math.abs(price - referencePrice) / referencePrice : 1;
 }

 function sahiKeyLevelStrength(count = 0) {
 const clusters = Math.max(0, Math.round(Number(count || 0)));
 if (clusters >= 15) return 'Strong';
 if (clusters >= 8) return 'Medium';
 if (clusters >= 4) return 'Weak';
 return 'Developing';
 }

 function sahiKeyLevelRoles() {
 return [
 { colorRole: 'resistance-major', color: 'red', roleLabel: '', label: 'Strong Resistance' },
 { colorRole: 'resistance-minor', color: 'orange', roleLabel: '', label: 'Breakout Retest Zone' },
 { colorRole: 'support-near', color: 'blue', roleLabel: '', label: 'Support Zone' },
 { colorRole: 'support-deep', color: 'yellow', roleLabel: '', label: 'Major Bottom Support' },
 ];
 }

 function applySahiKeyLevelRoles(zones = []) {
 const roles = sahiKeyLevelRoles();
 return (Array.isArray(zones) ? zones : [])
 .slice()
 .sort((a, b) => Number(b.price || b.mid || 0) - Number(a.price || a.mid || 0))
 .slice(0, 4)
 .map((zone, index) => ({
 ...zone,
 colorRole: roles[index]?.colorRole || zone.colorRole || '',
 color: roles[index]?.color || zone.color || '',
 roleLabel: roles[index]?.roleLabel || '',
 label: roles[index]?.label || zone.label || '',
 }));
 }

 function selectReadableSahiKeyZones(zones = [], referencePrice = 0, atrValue = 0) {
 const rows = (Array.isArray(zones) ? zones : [])
 .map(zone => ({
 ...zone,
 price: Number(zone.price || zone.mid || 0),
 zoneWidth: Number(zone.zoneWidth || Math.abs(Number(zone.zoneHigh || 0) - Number(zone.zoneLow || 0)) || 0),
 }))
 .filter(zone => Number(zone.price || 0) > 0);
 if (rows.length <= 4) return applySahiKeyLevelRoles(rows);
 const medianWidth = medianNumber(rows.map(zone => Number(zone.zoneWidth || 0)));
 const minGap = Math.max(
 Number(referencePrice || 0) > 0 ? Number(referencePrice || 0) * 0.004 : 0,
 Number(atrValue || 0) * 0.8,
 Number(medianWidth || 0) * 1.8
 );
 const rank = zone => (
 Number(zone.reactionClusterCount || zone.touch_count || zone.touches || 0) * 24
 + Number(zone.smartScore || zone.score || 0)
 + (Number(zone.fallback || 0) ? -10 : 0)
 );
 const selected = [];
 const addIfSpaced = zone => {
 if (!zone || selected.length >= 4) return false;
 const price = Number(zone.price || 0);
 if (!(price > 0)) return false;
 if (selected.some(item => Math.abs(Number(item.price || 0) - price) < minGap)) return false;
 selected.push(zone);
 return true;
 };
 rows.slice().sort((a, b) => rank(b) - rank(a)).forEach(addIfSpaced);
 if (selected.length < 4) {
 rows.slice()
 .filter(zone => !selected.includes(zone))
 .sort((a, b) => {
 const aGap = selected.length ? Math.min(...selected.map(item => Math.abs(Number(item.price || 0) - Number(a.price || 0)))) : Number.POSITIVE_INFINITY;
 const bGap = selected.length ? Math.min(...selected.map(item => Math.abs(Number(item.price || 0) - Number(b.price || 0)))) : Number.POSITIVE_INFINITY;
 if (Math.abs(bGap - aGap) > 1e-8) return bGap - aGap;
 return rank(b) - rank(a);
 })
 .forEach(zone => {
 if (selected.length < 4 && !selected.includes(zone)) selected.push(zone);
 });
 }
 return applySahiKeyLevelRoles(selected);
 }

 function chartTrueRange(candle = {}, previous = null) {
 const high = Number(candle.high || 0);
 const low = Number(candle.low || 0);
 const prevClose = Number(previous?.close || 0);
 if (!(high > 0) || !(low > 0) || high < low) return 0;
 if (!(prevClose > 0)) return high - low;
 return Math.max(high - low, Math.abs(high - prevClose), Math.abs(low - prevClose));
 }

 function chartAtrValue(candles = [], period = 14) {
 const rows = Array.isArray(candles) ? candles : [];
 if (rows.length < 2) return 0;
 const ranges = rows.map((candle, index) => chartTrueRange(candle, rows[index - 1] || null)).filter(value => Number.isFinite(value) && value > 0);
 if (!ranges.length) return 0;
 const sample = ranges.slice(-Math.max(1, Number(period || 14)));
 return sample.reduce((sum, value) => sum + value, 0) / sample.length;
 }

 function sahiZoneWidth(price = 0, atrValue = 0) {
 const mid = Number(price || 0);
 return Math.max(mid > 0 ? mid * 0.0015 : 0, Number(atrValue || 0) * 0.25);
 }

 function detectVisiblePivotLevels(candles = [], atrValue = 0, referencePrice = 0, settings = {}) {
 const pivotLength = Math.max(2, Math.min(20, Math.round(Number(settings?.pivotLength || 6) || 6)));
 const pivotMemory = Math.max(4, Math.min(200, Math.round(Number(settings?.pivotMemory || 50) || 50)));
 const rows = (Array.isArray(candles) ? candles : [])
 .map((candle, index) => ({
 index,
 time: Number(candle.time || 0),
 high: Number(candle.high || 0),
 low: Number(candle.low || 0),
 close: Number(candle.close || 0),
 }))
 .filter(candle => candle.time > 0 && candle.high > 0 && candle.low > 0 && candle.high >= candle.low);
 if (rows.length < 8) return [];
 const pivot = Math.max(2, Math.min(pivotLength, Math.floor((rows.length - 1) / 2)));
 const allPoints = [];
 for (let index = pivot; index < rows.length - pivot; index += 1) {
 const candle = rows[index];
 let isHigh = true;
 let isLow = true;
 for (let scan = index - pivot; scan <= index + pivot; scan += 1) {
 if (scan === index) continue;
 if (rows[scan].high >= candle.high) isHigh = false;
 if (rows[scan].low <= candle.low) isLow = false;
 if (!isHigh && !isLow) break;
 }
 if (isHigh) allPoints.push({ price: candle.high, time: candle.time, index, kind: 'resistance' });
 if (isLow) allPoints.push({ price: candle.low, time: candle.time, index, kind: 'support' });
 }
 let points = allPoints.slice(-pivotMemory);
 if (!points.length) {
 const highest = rows.reduce((best, candle) => candle.high > best.high ? candle : best, rows[0]);
 const lowest = rows.reduce((best, candle) => candle.low < best.low ? candle : best, rows[0]);
 points.push({ price: highest.high, time: highest.time, index: highest.index, kind: 'resistance' });
 points.push({ price: lowest.low, time: lowest.time, index: lowest.index, kind: 'support' });
 }
 const basePrice = Number(referencePrice || rows[rows.length - 1]?.close || 0);
 const tolerance = Math.max(basePrice > 0 ? basePrice * 0.0015 : 0, Number(atrValue || 0) * 0.25);
 const clusters = [];
 points.sort((a, b) => Number(a.price || 0) - Number(b.price || 0)).forEach(point => {
 const match = clusters.find(cluster => Math.abs(Number(point.price || 0) - Number(cluster.price || 0)) <= tolerance);
 if (!match) {
 clusters.push({
 price: point.price,
 kind: point.kind,
 touches: 1,
 lastIndex: point.index,
 lastTime: point.time,
 sourcePivots: [{ price: point.price, ts: point.time }],
 });
 return;
 }
 const oldWeight = Math.max(1, Number(match.touches || 1));
 const nextWeight = oldWeight + 1;
 match.price = ((Number(match.price || 0) * oldWeight) + Number(point.price || 0)) / nextWeight;
 match.touches = nextWeight;
 match.kind = Number(match.price || 0) >= basePrice ? 'resistance' : 'support';
 match.lastIndex = Math.max(Number(match.lastIndex || 0), Number(point.index || 0));
 match.lastTime = Math.max(Number(match.lastTime || 0), Number(point.time || 0));
 match.sourcePivots = [...(Array.isArray(match.sourcePivots) ? match.sourcePivots : []), { price: point.price, ts: point.time }].slice(-12);
 });
 const extrema = [
 rows.reduce((best, candle) => candle.high > best.high ? candle : best, rows[0]),
 rows.reduce((best, candle) => candle.low < best.low ? candle : best, rows[0]),
 ];
 extrema.forEach(candle => {
 const price = candle.high === extrema[0].high ? candle.high : candle.low;
 const kind = price >= basePrice ? 'resistance' : 'support';
 const nearExisting = clusters.some(cluster => Math.abs(Number(cluster.price || 0) - price) <= tolerance);
 if (!nearExisting) {
 clusters.push({
 price,
 kind,
 touches: 1,
 lastIndex: candle.index,
 lastTime: candle.time,
 sourcePivots: [{ price, ts: candle.time }],
 });
 }
 });
 if (clusters.length < 4) {
 const visibleHigh = Math.max(...rows.map(candle => Number(candle.high || 0)).filter(value => value > 0));
 const visibleLow = Math.min(...rows.map(candle => Number(candle.low || 0)).filter(value => value > 0));
 const visibleRange = Math.max(0, visibleHigh - visibleLow);
 [0.82, 0.64, 0.46, 0.28].forEach((ratio, index) => {
 if (clusters.length >= 4 || !(visibleRange > 0)) return;
 const price = visibleLow + visibleRange * ratio;
 const nearExisting = clusters.some(cluster => Math.abs(Number(cluster.price || 0) - price) <= tolerance);
 if (nearExisting) return;
 const nearest = rows.reduce((best, candle) => {
 const gap = Math.min(Math.abs(Number(candle.high || 0) - price), Math.abs(Number(candle.low || 0) - price), Math.abs(Number(candle.close || 0) - price));
 return !best || gap < best.gap ? { candle, gap } : best;
 }, null)?.candle || rows[Math.max(0, rows.length - 1 - index)];
 clusters.push({
 price,
 kind: price >= basePrice ? 'resistance' : 'support',
 touches: 1,
 lastIndex: nearest.index,
 lastTime: nearest.time,
 sourcePivots: [{ price, ts: nearest.time }],
 fallback: true,
 });
 });
 }
 return clusters
 .filter(cluster => Number(cluster.price || 0) > 0)
 .map(cluster => ({
 ...cluster,
 tf: 'visible',
 mid: Number(cluster.price || 0),
 score: Number(cluster.touches || 0) * 12 + Number(cluster.lastIndex || 0) / Math.max(1, rows.length),
 smartScore: Number(cluster.touches || 0) * 12 + Number(cluster.lastIndex || 0) / Math.max(1, rows.length),
 }));
 }

 function detectKeyLevelReactionEvent(candles = [], index = 0, zone = {}, width = 0) {
 const candle = candles[index] || {};
 const prev = candles[index - 1] || {};
 const low = Number(zone.zoneLow || zone.lower || zone.price || 0);
 const high = Number(zone.zoneHigh || zone.upper || zone.price || 0);
 const kind = zone.kind === 'resistance' ? 'resistance' : 'support';
 const close = Number(candle.close || 0);
 const open = Number(candle.open || 0);
 const candleLow = Number(candle.low || close || 0);
 const candleHigh = Number(candle.high || close || 0);
 const prevClose = Number(prev.close || 0);
 const time = Number(candle.time || 0);
 if (!(time > 0) || !(close > 0) || !(candleLow > 0) || !(candleHigh > 0) || !(low > 0) || !(high > 0)) return null;
 const range = Math.max(candleHigh - candleLow, close * 0.0001);
 const body = Math.max(Math.abs(close - open), range * 0.12);
 const touched = candleLow <= high && candleHigh >= low;
 const upperWick = Math.max(0, candleHigh - Math.max(open, close));
 const lowerWick = Math.max(0, Math.min(open, close) - candleLow);
 const nearWidth = Math.max(Number(width || 0), close * 0.0008);
 const nearLow = Math.max(0, low - nearWidth);
 const nearHigh = high + nearWidth;
 const lookback = candles.slice(Math.max(0, index - 5), index);
 const nearBars = lookback.filter(item => {
 const itemClose = Number(item.close || 0);
 const itemLow = Number(item.low || itemClose || 0);
 const itemHigh = Number(item.high || itemClose || 0);
 return itemClose >= nearLow && itemClose <= nearHigh && itemLow <= nearHigh && itemHigh >= nearLow;
 }).length;
 const hadCloseAbove = candles.slice(Math.max(0, index - 12), index).some(item => Number(item.close || 0) > high);
 const hadCloseBelow = candles.slice(Math.max(0, index - 12), index).some(item => Number(item.close || 0) < low);
 const breakoutUp = prevClose > 0 && prevClose <= high && close > high && (touched || nearBars >= 3);
 const breakoutDown = prevClose > 0 && prevClose >= low && close < low && (touched || nearBars >= 3);
 const retestAbove = touched && close > high && prevClose > high && hadCloseBelow;
 const retestBelow = touched && close < low && prevClose < low && hadCloseAbove;
 if (nearBars >= 3 && (breakoutUp || breakoutDown)) {
 return { type: 'consolidation-breakout', index, time, price: close, score: 5 + nearBars };
 }
 if (retestAbove || retestBelow) return { type: 'retest', index, time, price: close, score: 8 };
 if (breakoutUp || breakoutDown) return { type: 'breakout', index, time, price: close, score: 6 };
 if (!touched) return null;
 if (kind === 'resistance') {
 const wickReject = upperWick >= Math.max(body * 0.65, range * 0.24);
 if (wickReject && close < high) return { type: 'rejection', index, time, price: Math.min(candleHigh, high), score: 7 + (upperWick / range) };
 } else {
 const wickBounce = lowerWick >= Math.max(body * 0.65, range * 0.24);
 if (wickBounce && close > low) return { type: 'bounce', index, time, price: Math.max(candleLow, low), score: 7 + (lowerWick / range) };
 }
 return null;
 }

 function clusterKeyLevelReactionEvents(events = [], mergeWindow = 10) {
 const sorted = (Array.isArray(events) ? events : [])
 .filter(event => Number(event?.index || 0) >= 0 && Number(event?.time || 0) > 0)
 .sort((a, b) => Number(a.index || 0) - Number(b.index || 0));
 const clusters = [];
 sorted.forEach(event => {
 const last = clusters[clusters.length - 1];
 if (last && Number(event.index || 0) - Number(last.endIndex || 0) <= mergeWindow) {
 last.endIndex = Number(event.index || 0);
 last.events += 1;
 if (Number(event.score || 0) >= Number(last.marker.score || 0)) last.marker = event;
 return;
 }
 clusters.push({ startIndex: Number(event.index || 0), endIndex: Number(event.index || 0), events: 1, marker: event });
 });
 return clusters;
 }

 function keyLevelState(zone = {}, candles = [], referencePrice = 0) {
 const recent = (Array.isArray(candles) ? candles : []).slice(-8);
 const last = recent[recent.length - 1] || {};
 const prev = recent[recent.length - 2] || {};
 const price = Number(zone.price || 0);
 const low = Number(zone.zoneLow || price || 0);
 const high = Number(zone.zoneHigh || price || 0);
 const close = Number(last.close || referencePrice || 0);
 const prevClose = Number(prev.close || 0);
 const lastLow = Number(last.low || close || 0);
 const lastHigh = Number(last.high || close || 0);
 const inside = close >= low && close <= high;
 const touched = lastLow <= high && lastHigh >= low;
 const fromAbove = prevClose > high;
 const fromBelow = prevClose < low;
 if (inside || touched) return { state: 'near', label: 'Near level', tone: 'watch' };
 if (zone.kind === 'resistance') {
 if (prevClose <= high && close > high) return { state: 'broken_above', label: 'Broken above', tone: 'good' };
 if (fromAbove && lastLow <= high && close > high) return { state: 'retest', label: 'Retest above', tone: 'good' };
 if (fromBelow && lastHigh >= low && close < low) return { state: 'rejecting_resistance', label: 'Rejecting resistance', tone: 'danger' };
 return close > high ? { state: 'above_resistance', label: 'Above resistance', tone: 'neutral' } : { state: 'below_resistance', label: 'Below resistance', tone: 'watch' };
 }
 if (prevClose >= low && close < low) return { state: 'broken_below', label: 'Broken below', tone: 'danger' };
 if (fromBelow && lastHigh >= low && close < low) return { state: 'retest', label: 'Retest below', tone: 'danger' };
 if (fromAbove && lastLow <= high && close > high) return { state: 'holding_support', label: 'Holding support', tone: 'good' };
 return close < low ? { state: 'below_support', label: 'Below support', tone: 'danger' } : { state: 'above_support', label: 'Above support', tone: 'watch' };
 }

 function buildKeyLevelReactionData(zone = {}, candles = [], referencePrice = 0) {
 const price = Number(zone.price || 0);
 const low = Number(zone.zoneLow || price || 0);
 const high = Number(zone.zoneHigh || price || 0);
 const source = Array.isArray(candles) ? candles : [];
 const width = Math.max(Math.abs(high - low), price > 0 ? price * 0.0015 : 0);
 const events = [];
 for (let index = 1; index < source.length; index++) {
 const event = detectKeyLevelReactionEvent(source, index, zone, width);
 if (event) events.push(event);
 }
 const clusters = clusterKeyLevelReactionEvents(events, 10);
 const markers = clusters.map(cluster => ({
 type: cluster.marker?.type || 'reaction',
 time: Number(cluster.marker?.time || 0),
 price: Number(cluster.marker?.price || price || 0),
 clusterSize: Number(cluster.events || 1),
 index: Number(cluster.marker?.index || 0),
 }));
 const respected = markers.filter(marker => ['bounce', 'rejection', 'retest'].includes(marker.type)).length;
 const total = clusters.length;
 const quality = total > 0 ? Math.round((respected / total) * 100) : 0;
 const latestTouchTime = markers.length ? Number(markers[markers.length - 1].time || 0) : Math.max(...(Array.isArray(zone.sourcePivots) ? zone.sourcePivots : []).map(pivot => Number(pivot.ts || 0)).filter(Boolean), 0);
 const distancePct = keyLevelDistancePct(zone, referencePrice);
 const clusterCount = clusters.length;
 const markerLimit = 18;
 return {
 reactionQuality: quality,
 latestTouchTime,
 distancePct,
 isFar: distancePct > 0.05,
 reactionClusterCount: clusterCount,
 touch_count: clusterCount,
 touches: clusterCount,
 strength: sahiKeyLevelStrength(clusterCount),
 reactionMarkers: markers.slice(-markerLimit),
 };
 }

 function rankSahiKeyZones(zones = [], settings = {}, referencePrice = 0, chartTimeframe = '4h') {
 const limit = 4;
 const byKind = ['resistance', 'support'].flatMap(kind => {
 return mergeNearbyKeyZones(
 (Array.isArray(zones) ? zones : []).filter(zone => zone.kind === kind),
 referencePrice,
 { ...settings, chartTimeframe }
 )
 .map(zone => ({
 ...zone,
 smartScore: scoreKeyZone(zone, referencePrice, kind),
 }));
 });
 const strong = byKind.filter(zone => Number(zone.touches || 0) >= 2 || Number(zone.strengthPct || 0) >= 12);
 const ranked = (strong.length ? strong : byKind)
 .sort((a, b) => {
 const scoreDiff = Number(b.smartScore || 0) - Number(a.smartScore || 0);
 if (scoreDiff) return scoreDiff;
 const touchDiff = Number(b.touches || 0) - Number(a.touches || 0);
 if (touchDiff) return touchDiff;
 if (referencePrice > 0) {
 const distanceDiff = Math.abs(Number(a.price || 0) - referencePrice) - Math.abs(Number(b.price || 0) - referencePrice);
 if (distanceDiff) return distanceDiff;
 }
 return Number(b.price || 0) - Number(a.price || 0);
 });
 const selected = [];
 const addUnique = (zone = null) => {
 if (!zone || selected.length >= limit) return;
 const key = `${zone.kind}:${Math.round(Number(zone.price || 0) * 1000000)}`;
 if (selected.some(item => `${item.kind}:${Math.round(Number(item.price || 0) * 1000000)}` === key)) return;
 selected.push(zone);
 };
 if (limit >= 2) {
 addUnique(ranked.find(zone => zone.kind === 'resistance'));
 addUnique(ranked.find(zone => zone.kind === 'support'));
 }
 ranked.forEach(addUnique);
 const visible = applySahiKeyLevelRoles(selected.slice(0, limit));
 return visible.map(zone => ({
 ...zone,
 upper: Number(zone.zoneHigh || zone.upper || zone.price || 0),
 lower: Number(zone.zoneLow || zone.lower || zone.price || 0),
 mid: Number(zone.price || zone.mid || 0),
 type: zone.kind === 'resistance' ? 'Resistance' : 'Support',
 touch_count: Math.max(0, Math.round(Number(zone.touch_count || zone.touches || 0))),
 }));
 }

 function chooseSmartKeyZones(zones = [], settings = {}, referencePrice = 0, kind = 'support') {
 const density = normalizeOverlayDensity(settings.overlayDensity || '');
 const chartTf = normalizeTimeframe(settings.chartTimeframe || '');
 const dailyContext = chartTf === '1d' || chartTf === '1h' || chartTf === '4h';
 const rawLimit = Math.max(1, Math.min(8, Math.floor(settings.numberOfLevels || 4)));
 const limit = dailyContext && density === 'minimal' ? Math.min(rawLimit, 2) : rawLimit;
 const merged = mergeNearbyKeyZones(zones, referencePrice, settings)
 .map(zone => ({ ...zone, smartScore: scoreKeyZone(zone, referencePrice, kind) }))
 .sort((a, b) => Number(b.smartScore || 0) - Number(a.smartScore || 0));
 const strong = merged.filter(zone => Number(zone.touches || 0) >= 2 || Number(zone.strengthPct || 0) >= 12);
 const source = strong.length ? strong : merged;
 return source
 .slice(0, limit)
 .sort((a, b) => kind === 'resistance' ? Number(a.price || 0) - Number(b.price || 0) : Number(b.price || 0) - Number(a.price || 0));
 }

 function mapChartTfToKeyLevelTf(chartTimeframe = '4h') {
 const tf = normalizeTimeframe(chartTimeframe);
 if (tf === '1d') return '1D';
 if (['4h', '1h'].includes(tf)) return '1D';
 return '4h';
 }

 function collectVisibleKeyZones(keyLevels = null, settings = {}, referencePrice = 0, chartTimeframe = '4h') {
 if (!keyLevels || typeof keyLevels !== 'object') return [];
 const smartSettings = { ...settings, chartTimeframe };
 const brokerZones = [
 ...(Array.isArray(keyLevels.smartLevels) ? keyLevels.smartLevels : []),
 ...(Array.isArray(keyLevels.majorLevels) ? keyLevels.majorLevels : []),
 ...(Array.isArray(keyLevels.levels) ? keyLevels.levels : []),
 ].map(zone => normalizeKeyZone(zone, zone?.kind || zone?.type || 'support', zone?.tf || 'combined')).filter(Boolean);
 if (brokerZones.length) return rankSahiKeyZones(brokerZones, smartSettings, referencePrice, chartTimeframe);
 if (!keyLevels?.byTimeframe) return [];
 const primaryTf = mapChartTfToKeyLevelTf(chartTimeframe);
 const primaryBucket = keyLevels.byTimeframe?.[primaryTf];
 const zones = [];
 if (primaryBucket) {
 ['resistance', 'support'].forEach(kind => {
 (Array.isArray(primaryBucket[kind]) ? primaryBucket[kind] : []).forEach(zone => {
 const normalized = normalizeKeyZone(zone, kind, primaryTf);
 if (!normalized) return;
 zones.push({
 ...normalized,
 tf: primaryTf,
 displayStrengthAs: settings.displayStrengthAs,
 showPivotCircles: settings.showPivotCircles,
 showLevelGlow: settings.showLevelGlow,
 thickness: settings.thickness,
 });
 });
 });
 }
 ['resistance', 'support'].forEach(kind => {
 (Array.isArray(keyLevels[kind]) ? keyLevels[kind] : []).forEach(zone => {
 const normalized = normalizeKeyZone(zone, kind, 'combined');
 if (!normalized) return;
 zones.push({
 ...normalized,
 tf: 'combined',
 displayStrengthAs: settings.displayStrengthAs,
 showPivotCircles: settings.showPivotCircles,
 showLevelGlow: settings.showLevelGlow,
 thickness: settings.thickness,
 });
 });
 });
 return rankSahiKeyZones(zones, smartSettings, referencePrice, chartTimeframe);
 }

// Replay, axes, panels, chart model and chart markup builders
 function buildOrderContextFromDraft(draft = {}, preview = null) {
 const symbol = String(draft.symbol || preview?.productSymbol || '').trim().toUpperCase();
 const lines = [
 { key: 'mark', label: 'Mark', tone: 'mark', price: Number(preview?.markPrice || draft.freshMarkPrice || 0), source: 'preview' },
 { key: 'entry', label: 'Entry', tone: 'entry', price: Number(draft.entry || preview?.entryReference || 0), source: 'preview' },
 { key: 'stop', label: 'Stop', tone: 'stop', price: Number(draft.stopLoss || 0), source: 'preview' },
 { key: 'target', label: 'Target', tone: 'target', price: Number(draft.takeProfit || 0), source: 'preview' },
 ].map(normalizeOrderLine).filter(Boolean);
 return normalizeOrderContext({
 source: 'preview',
 label: symbol ? `${symbol} live order` : 'Live order',
 symbol,
 lines,
 linkedOrders: [],
 });
 }

 function buildOrderContextFromPosition(position = {}, linked = null) {
 const lines = [
 { key: 'entry', label: 'Entry', tone: 'entry', price: Number(position.entry || 0), source: 'position' },
 { key: 'mark', label: 'Mark', tone: 'mark', price: Number(position.markPrice || 0), source: 'position' },
 ];
 const linkedOrders = Array.isArray(linked?.all) ? linked.all : [];
 linkedOrders.forEach(order => {
 const price = Number(order.stopPrice || order.limitPrice || order.price || 0);
 if (!(price > 0)) return;
 const role = String(order.role || '').toLowerCase();
 lines.push({
 key: `${role || 'order'}_${order.orderId || order.clientOrderId || price}`,
 label: role === 'stop_loss'
 ? 'Stop'
 : role === 'take_profit'
 ? 'Target'
 : role === 'entry'
 ? 'Entry Ord'
 : role === 'exit'
 ? 'Exit Ord'
 : 'Order',
 tone: role === 'stop_loss'
 ? 'stop'
 : role === 'take_profit'
 ? 'target'
 : role === 'entry'
 ? 'entry'
 : 'mark',
 price,
 source: 'linked',
 kind: role,
 role,
 orderId: String(order.orderId || order.id || '').trim(),
 clientOrderId: String(order.clientOrderId || '').trim(),
 meta: order.reduceOnly ? 'Reduce only' : '',
 });
 });
 return normalizeOrderContext({
 source: 'position',
 label: `${String(position.symbol || '').trim().toUpperCase()} linked orders`,
 symbol: String(position.symbol || '').trim().toUpperCase(),
 lines,
 linkedOrders,
 position: {
 symbol: String(position.symbol || '').trim().toUpperCase(),
 side: String(position.side || position.direction || '').trim().toLowerCase(),
 size: Number(position.size || position.contracts || position.quantity || 0) || 0,
 entry: Number(position.entry || position.entryPrice || 0) || 0,
 markPrice: Number(position.markPrice || position.price || 0) || 0,
 productId: Number(position.productId || 0) || 0,
 },
 });
 }

 function deriveReplayTimeframe(trade = {}) {
 const openedAt = normalizeTsMs(trade.openedAt || trade.entryTs || trade.entryTime);
 const closedAt = normalizeTsMs(trade.closedAt || trade.exitTs || trade.exitTime);
 const durationMs = Math.max(0, closedAt - openedAt);
 if (durationMs <= 3 * 24 * 60 * 60 * 1000) return '4h';
 if (durationMs <= 14 * 24 * 60 * 60 * 1000) return '4h';
 return '4h';
}

 function buildReplaySeedFromTrade(trade = {}) {
 const entryTs = normalizeTsMs(trade.openedAt || trade.entryTs || trade.entryTime);
 const exitTs = normalizeTsMs(trade.closedAt || trade.exitTs || trade.exitTime);
 const entryPrice = Number(trade.entryPrice || trade.entry || 0);
 const exitPrice = Number(trade.exitPrice || trade.exit || 0);
 const stopPrice = Number(trade.stopLoss || trade.sl || 0);
 const markers = [
 { key: 'entry', label: 'Entry', price: entryPrice, ts: entryTs, tone: 'entry' },
 { key: 'exit', label: 'Exit', price: exitPrice, ts: exitTs, tone: 'target' },
 { key: 'stop', label: 'Stop', price: stopPrice, ts: exitTs || entryTs, tone: 'mark' },
 ];
 (Array.isArray(trade.targetShiftEvents) ? trade.targetShiftEvents : []).forEach((event, index) => {
 const nextTarget = Number(event?.newTargetPrice || 0);
 const shiftedAt = normalizeTsMs(event?.shiftedAt || 0);
 const toLabel = String(event?.toTargetLabel || event?.toStage || `T${index + 2}`).trim().toUpperCase() || `T${index + 2}`;
 if (nextTarget > 0 && shiftedAt > 0) {
 markers.push({
 key: `shift_${index}`,
 label: `${toLabel} Live`,
 price: nextTarget,
 ts: shiftedAt,
 tone: 'target',
 });
 }
 });
 return normalizeReplaySeed({
 source: 'journal',
 beforeCount: 60,
 afterCount: 60,
 entryTs,
 exitTs,
 baselineVisibleCount: 121,
 label: trade.symbol ? `${trade.symbol} replay` : 'Trade replay',
 markers: markers.filter(marker => marker.price > 0 && marker.ts > 0),
 });
 }

 function buildAxisLabels(candles = [], timeframe = '4h', startIndex = 0) {
 const labels = [];
 const verticals = [];
 if (!candles.length) return { labels, verticals };
 const every = Math.max(1, Math.round(candles.length / 6));
 candles.forEach((candle, index) => {
 const date = new Date(Number(candle.time || 0));
 const leftPct = (index / Math.max(1, candles.length - 1)) * 100;
 const prev = index > 0 ? new Date(Number(candles[index - 1]?.time || 0)) : null;
 const dayChanged = prev ? (
 date.getUTCDate() !== prev.getUTCDate()
 || date.getUTCMonth() !== prev.getUTCMonth()
 || date.getUTCFullYear() !== prev.getUTCFullYear()
 ) : false;
 const monthChanged = prev ? (
 date.getUTCMonth() !== prev.getUTCMonth()
 || date.getUTCFullYear() !== prev.getUTCFullYear()
 ) : false;
 const yearChanged = prev ? date.getUTCFullYear() !== prev.getUTCFullYear() : false;
 let label = '';
 if (timeframe === '1h' || timeframe === '4h') {
 if (dayChanged) {
 label = date.toLocaleDateString([], { month: 'short', day: 'numeric' });
 verticals.push({ leftPct, label });
 } else if (index % every === 0 || index === candles.length - 1) {
 label = date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
 }
 } else if (timeframe === '1d') {
 if (monthChanged || index % every === 0 || index === candles.length - 1) {
 label = date.toLocaleDateString([], { month: 'short', day: 'numeric' });
 }
 } else {
 if (yearChanged) {
 label = String(date.getUTCFullYear());
 verticals.push({ leftPct, label });
 } else if (monthChanged || index % every === 0 || index === candles.length - 1) {
 label = date.toLocaleDateString([], { month: 'short' });
 }
 }
 if (!label) return;
 labels.push({
 key: `${startIndex + index}_${label}`,
 leftPct,
 label,
 });
 });
 return { labels, verticals };
 }

 function buildSvgPath(points = []) {
 return points.reduce((acc, point, index) => {
 const x = Number(point.x || 0).toFixed(2);
 const y = Number(point.y || 0).toFixed(2);
 return `${acc}${index ? ' L ' : 'M '}${x} ${y}`;
 }, '');
 }

 function formatIntelMetric(metric = {}) {
 if (metric.format === 'price') return `Rs ${formatPrice(metric.value)}`;
 return String(metric.value == null ? '-' : metric.value);
 }

 function buildActiveIndicatorChips(state = {}, presetMeta = {}) {
 const indicators = sanitizeIndicatorState(state.indicators || {});
 const chips = [];
 if (indicators.volume) chips.push('Volume');
 if (indicators.ema || presetMeta.showEma) chips.push('EMA');
 if (indicators.sma || presetMeta.showSma) chips.push('SMA');
 if (state.showVwap || indicators.vwap || presetMeta.showVwap) chips.push('VWAP');
 if (indicators.bollinger || presetMeta.showBollinger) chips.push('Bollinger');
 if (indicators.supertrend || presetMeta.showSupertrend) chips.push('Supertrend');
 if (indicators.rsi || presetMeta.showRsi) chips.push('RSI');
 if (indicators.macd || presetMeta.showMacd) chips.push('MACD');
 if (indicators.obv || presetMeta.showObv) chips.push('OBV');
 if (indicators.atr || presetMeta.showAtr) chips.push('ATR');
 if (indicators.darvas) chips.push('Darvas Box');
 return chips.slice(0, 8);
 }

 function latestFinite(values = []) {
 if (!Array.isArray(values)) return null;
 for (let index = values.length - 1; index >= 0; index -= 1) {
 const numeric = Number(values[index]);
 if (Number.isFinite(numeric)) return numeric;
 }
 return null;
 }

 function formatIndicatorValue(value = null, kind = 'price') {
 const numeric = Number(value);
 if (!Number.isFinite(numeric)) return '-';
 if (kind === 'volume') {
 const abs = Math.abs(numeric);
 if (abs >= 1e9) return `${(numeric / 1e9).toFixed(2)}B`;
 if (abs >= 1e6) return `${(numeric / 1e6).toFixed(2)}M`;
 if (abs >= 1e3) return `${(numeric / 1e3).toFixed(1)}K`;
 return String(Math.round(numeric));
 }
 return formatPrice(numeric);
 }

 function isIndicatorGroupActive(state = {}, presetMeta = {}, key = '') {
 const raw = sanitizeIndicatorState(state.indicators || {});
 const presetId = String(presetMeta.id || state.preset || '').trim().toLowerCase();
 if ((presetId === 'key' || presetId === 'clean') && ['ema', 'sma', 'bollinger', 'supertrend', 'rsi', 'macd', 'obv', 'atr'].includes(key)) return false;
 if (raw[`${key}Removed`] === true) return false;
 if (key === 'darvas') return raw.darvas === true;
 if (key === 'ema') return raw.ema === true || !!presetMeta.showEma;
 if (key === 'sma') return raw.sma === true || !!presetMeta.showSma;
 if (key === 'vwap') return state.showVwap === true || raw.vwap === true || !!presetMeta.showVwap;
 if (key === 'bollinger') return raw.bollinger === true || !!presetMeta.showBollinger;
 if (key === 'supertrend') return raw.supertrend === true || !!presetMeta.showSupertrend;
 if (key === 'rsi') return raw.rsi === true || !!presetMeta.showRsi;
 if (key === 'macd') return raw.macd === true || !!presetMeta.showMacd;
 if (key === 'obv') return raw.obv === true || !!presetMeta.showObv;
 if (key === 'atr') return raw.atr === true || !!presetMeta.showAtr;
 return raw[key] === true;
 }

