 function bindKeyboardShortcuts(surface = SURFACE_DETACHED) {
 if (surface !== SURFACE_DETACHED) return;
 if (keyboardShortcutSurfacesBound.has(surface)) return;
 keyboardShortcutSurfacesBound.add(surface);
 document.addEventListener('keydown', async event => {
 const key = event.key;
 if (key === 'ArrowLeft' || key === 'ArrowRight') {
 event.preventDefault();
 const step = event.shiftKey ? 10 : 1;
 const action = key === 'ArrowLeft' ? (step === 10 ? 'back10' : 'back') : (step === 10 ? 'forward10' : 'forward');
 await updateChartState(surface, currentState => updateReplayCursorState(currentState, action), { forceRender: true });
 } else if (key === '+' || key === '=') {
 event.preventDefault();
 await updateChartState(surface, currentState => {
 const current = Number(currentState.visibleCandleCount || defaultVisibleCount(currentState.timeframe));
 return { visibleCandleCount: Math.max(24, current - Math.max(4, Math.round(current * 0.15))) };
 });
 } else if (key === '-') {
 event.preventDefault();
 await updateChartState(surface, currentState => {
 const current = Number(currentState.visibleCandleCount || defaultVisibleCount(currentState.timeframe));
 return { visibleCandleCount: Math.min(MAX_RENDER_CANDLES, current + Math.max(4, Math.round(current * 0.15))) };
 });
 } else if (key === '0') {
 event.preventDefault();
 await updateChartState(surface, currentState => {
 const baseline = currentState.replaySeed?.baselineVisibleCount || defaultVisibleCount(currentState.timeframe);
 return { visibleCandleCount: baseline, replayMode: currentState.replayMode ? { ...currentState.replayMode, cursorIndex: null, playing: false } : null, replaySeed: currentState.replaySeed ? { ...currentState.replaySeed, cursorOffset: 0 } : null };
 });
 }
 });
 }

 function bindStorageListener() {
 if (storageListenerBound || !chrome.storage?.onChanged) return;
 storageListenerBound = true;
 let storageDebounceTimer = null;
 chrome.storage.onChanged.addListener((changes, areaName) => {
 if (areaName !== 'local') return;
 const changedKeys = Object.keys(changes || {});
 if (!changedKeys.length) return;
 const relevant =
 changedKeys.includes(DS_V17_CHART_STATE_KEY) ||
 changedKeys.includes('strategy') ||
 changedKeys.includes(DS_V17_CHART_CACHE_KEY);
 if (!relevant) return;
 clearTimeout(storageDebounceTimer);
 storageDebounceTimer = setTimeout(() => {
 void queueSurfaceRender(SURFACE_PREVIEW);
 void queueSurfaceRender(SURFACE_TAB);
 void queueSurfaceRender(SURFACE_DETACHED);
 }, 150);
 });
 }

